function startErrorResponse(error48, fallbackCode, fallbackMessage, context = {}) {
  if (error48 instanceof Error) {
    const code = error48.code;
    const status = error48.status;
    const changedFiles = error48.changedFiles;
    if (code === "uncommitted_changes") {
      log31.warn("Loop start blocked by uncommitted changes", {
        ...context,
        error: error48.message,
        changedFilesCount: changedFiles?.length ?? 0
      });
      return Response.json({
        error: "uncommitted_changes",
        message: error48.message,
        changedFiles: changedFiles ?? []
      }, { status: status ?? 409 });
    }
    if (code === "directory_in_use") {
      log31.warn("Loop start blocked because the directory is already in use", {
        ...context,
        error: error48.message
      });
      return errorResponse("directory_in_use", error48.message, status ?? 409);
    }
  }
  log31.error("Loop start failed", {
    ...context,
    error: String(error48),
    fallbackCode
  });
  return errorResponse(fallbackCode, `${fallbackMessage}: ${String(error48)}`, 500);
}

