    const git2 = GitService.withExecutor(executor);
    const originalBranch = chat3.state.worktree?.originalBranch ?? chat3.config.baseBranch ?? await git2.getCurrentBranch(chat3.config.directory);
    const workingBranch = chat3.state.worktree?.workingBranch ?? this.buildWorkingBranchName(chat3);
